module top_module(
  A,
  B,
  CIN,
  SUM,
  COUT
);input A;
  input B;
  input CIN;
  output SUM;
  output COUT;

  wire unused_w1, w2, w3;

  // XOR gate to calculate SUM
  xor(unused_w1, A, B);
  xor(SUM, unused_w1, CIN);

  // AND gate to calculate COUT
  and(w2, A, B);
  and(w3, unused_w1, CIN);
  or(COUT, w2, w3);
endmodule
